/**
 * Generate template_clause test data based on pattern
 *
 * @param pattern - The test data pattern to generate
 * @param overrides - Optional field overrides
 * @returns Generated test data
 *
 * @example
 * ```typescript
 * // Generate complete test data
 * const data = generateTemplateClauseTestData('complete');
 *
 * // Generate unique test data with overrides
 * const customData = generateTemplateClauseTestData('unique', {
 *   is_active: false,
 * });
 * ```
 */
export function generateTemplateClauseTestData(
  pattern: TestDataPattern = 'complete',
  overrides: Partial<TemplateClauseCreateRequest> = {}
): TemplateClauseCreateRequest {
  let baseData: TemplateClauseCreateRequest;

  switch (pattern) {
    case 'minimal':
      baseData = { ...minimalTemplateClauseFixture };
      break;

    case 'complete':
      baseData = { ...completeTemplateClauseFixture };
      break;

    case 'invalid':
      // Return invalid data (caller should handle validation failure)
      baseData = { ...invalidTemplateClauseFixture } as TemplateClauseCreateRequest;
      break;

    case 'unique':
      // Generate fresh unique values for each call
      baseData = {
        ...uniqueTemplateClauseFixture,
        name: `Test TemplateClause ${generateUniqueId()}`,
      };
      break;

    default:
      baseData = { ...completeTemplateClauseFixture };
  }

  return { ...baseData, ...overrides };
}

/**
 * Generate multiple template_clause fixtures
 *
 * @param count - Number of fixtures to generate
 * @param pattern - The test data pattern to use as base
 * @param modifier - Optional function to modify each fixture
 * @returns Array of generated test data
 *
 * @example
 * ```typescript
 * // Generate 5 unique fixtures
 * const fixtures = generateMultipleTemplateClauseFixtures(5, 'unique');
 *
 * // Generate fixtures with sequential numbering
 * const numbered = generateMultipleTemplateClauseFixtures(3, 'complete', (data, index) => ({
 *   ...data,
 *   name: `TemplateClause #${index + 1}`,
 * }));
 * ```
 */
export function generateMultipleTemplateClauseFixtures(
  count: number,
  pattern: TestDataPattern = 'unique',
  modifier?: (data: TemplateClauseCreateRequest, index: number) => TemplateClauseCreateRequest
): TemplateClauseCreateRequest[] {
  const fixtures: TemplateClauseCreateRequest[] = [];

  for (let i = 0; i < count; i++) {
    let fixture = generateTemplateClauseTestData(pattern);

    if (modifier) {
      fixture = modifier(fixture, i);
    } else if (pattern === 'unique') {
      // Add index to ensure uniqueness even with same timestamp
      fixture.name = `Test TemplateClause ${generateUniqueId()}-${i}`;
    }

    fixtures.push(fixture);
  }

  return fixtures;
}

